// =============================================================================
// NativeEngineConfig -- Builder for GoudGame via FFI
// =============================================================================

#[napi(js_name = "NativeEngineConfig")]
pub struct NativeEngineConfig {
    handle: *mut std::ffi::c_void,
    title: String,
}

#[napi]
impl NativeEngineConfig {
    #[napi(constructor)]
    pub fn new() -> Self {
        let handle = goud_engine::ffi::engine_config::goud_engine_config_create();
        Self {
            handle,
            title: String::new(),
        }
    }

    #[napi]
    pub fn set_title(&mut self, title: String) -> bool {
        if self.handle.is_null() {
            return false;
        }
        let c_title = match CString::new(title.clone()) {
            Ok(s) => s,
            Err(_) => return false,
        };
        self.title = title;
        // SAFETY: handle is valid, CString guarantees null-terminated.
        unsafe {
            goud_engine::ffi::engine_config::goud_engine_config_set_title(
                self.handle,
                c_title.as_ptr(),
            )
        }
    }

    #[napi]
    pub fn set_size(&self, width: u32, height: u32) -> bool {
        if self.handle.is_null() {
            return false;
        }
        // SAFETY: handle is valid.
        unsafe {
            goud_engine::ffi::engine_config::goud_engine_config_set_size(self.handle, width, height)
        }
    }

    #[napi]
    pub fn set_vsync(&self, enabled: bool) -> bool {
        if self.handle.is_null() {
            return false;
        }
        // SAFETY: handle is valid.
        unsafe {
            goud_engine::ffi::engine_config::goud_engine_config_set_vsync(self.handle, enabled)
        }
    }

    #[napi]
    pub fn set_fullscreen(&self, enabled: bool) -> bool {
        if self.handle.is_null() {
            return false;
        }
        // SAFETY: handle is valid.
        unsafe {
            goud_engine::ffi::engine_config::goud_engine_config_set_fullscreen(self.handle, enabled)
        }
    }

    #[napi]
    pub fn set_target_fps(&self, fps: u32) -> bool {
        if self.handle.is_null() {
            return false;
        }
        // SAFETY: handle is valid.
        unsafe {
            goud_engine::ffi::engine_config::goud_engine_config_set_target_fps(self.handle, fps)
        }
    }

    #[napi]
    pub fn set_fps_overlay(&self, enabled: bool) -> bool {
        if self.handle.is_null() {
            return false;
        }
        // SAFETY: handle is valid.
        unsafe {
            goud_engine::ffi::engine_config::goud_engine_config_set_fps_overlay(
                self.handle,
                enabled,
            )
        }
    }

    #[napi]
    pub fn set_physics_backend_2d(&self, backend: u32) -> bool {
        if self.handle.is_null() {
            return false;
        }
        // SAFETY: handle is valid.
        unsafe {
            goud_engine::ffi::engine_config::goud_engine_config_set_physics_backend_2d(
                self.handle,
                backend,
            )
        }
    }

    #[napi]
    pub fn set_debugger(&self, debugger: NapiDebuggerConfig) -> bool {
        if self.handle.is_null() {
            return false;
        }
        let route_label = match CString::new(debugger.route_label) {
            Ok(label) => label,
            Err(_) => return false,
        };
        let ffi_debugger = GoudDebuggerConfig {
            enabled: debugger.enabled,
            publish_local_attach: debugger.publish_local_attach,
            route_label: route_label.as_ptr(),
        };
        unsafe {
            goud_engine::ffi::engine_config::goud_engine_config_set_debugger(
                self.handle,
                &ffi_debugger,
            )
        }
    }

    #[napi]
    pub fn build(&mut self) -> Result<GoudGame> {
        if self.handle.is_null() {
            return Err(Error::from_reason("EngineConfig already consumed"));
        }
        let handle = self.handle;
        self.handle = std::ptr::null_mut();
        // SAFETY: handle is valid and we take ownership.
        let context_id = unsafe { goud_engine::ffi::engine_config::goud_engine_create(handle) };
        if context_id == GOUD_INVALID_CONTEXT_ID {
            return Err(Error::from_reason("Failed to create engine from config"));
        }
        Ok(GoudGame {
            context_id,
            last_delta_time: 0.0,
            title: std::mem::take(&mut self.title),
            frame_count: 0,
            total_time: 0.0,
        })
    }

    #[napi]
    pub fn destroy(&mut self) {
        if !self.handle.is_null() {
            // SAFETY: handle is valid and we own it.
            unsafe { goud_engine::ffi::engine_config::goud_engine_config_destroy(self.handle) };
            self.handle = std::ptr::null_mut();
        }
    }
}

// =============================================================================
